import requests
import pandas as pd
from io import StringIO

LIPIDMAPS_URL = "https://www.lipidmaps.org/ms/rest/ms_search/"

def _get_num_matches(db, mzStr, adducts, tolerance=0.001):
    """Return the number of unique m/z values that match in the LipidMaps database."""
    # Preprocess mzStr: ignore comment lines (starting with '#') and blank lines
    lines = mzStr.split('\n')
    valid_lines = []
    for line in lines:
        stripped = line.strip()
        if stripped == '' or stripped.startswith('#'):
            continue
        # Ensure the line can be parsed as a float (optional, but good practice)
        try:
            float(stripped)
            valid_lines.append(stripped)
        except ValueError:
            # Skip non-numeric lines (e.g., malformed)
            continue
    mzStr = '\n'.join(valid_lines)

    # Prepare multipart form data
    files = {'file': ('file', StringIO(mzStr), 'text/plain')}
    data = {
        'CHOICE': db,
        'ion': adducts,
        'tol': str(tolerance),
        'sort': 'DELTA'
    }
    try:
        response = requests.post(LIPIDMAPS_URL, data=data, files=files)
    except:
        raise Exception(
            'Connection error with the database. Please check your network and try again after a few minutes.'
        )
    if len(response.text) == 0:
        return 0
    else:
        matches = pd.read_csv(StringIO(response.text), sep='\t', engine='python', index_col=False)
        if matches.empty:
            return 0
        else:
            # Try to use 'Input Mass' column; fallback to first column if not present
            try:
                unique_masses = matches['Input Mass'].unique()
            except KeyError:
                # Use the first column (assuming it represents input mass)
                unique_masses = matches.iloc[:, 0].unique()
            return len(unique_masses)

def main():
    # Specify which LipidMaps database to query (e.g. 'GLYCOLIPIDS')
    db = 'GLYCOLIPIDS'
    # Create a string with one m/z value per line
    mz_values = '# comment line\n100.0\n\n200.0\n# another comment\n300.0\n'
    # Choose adducts of interest
    adducts = 'M+H,M+Na'
    # Set mass tolerance in Daltons
    tolerance = 0.01

    # CALL THE SOLUTION FUNCTION HERE
    num_matches = _get_num_matches(db, mz_values, adducts, tolerance)

    print(f'Number of unique m/z matches: {num_matches}')

if __name__ == '__main__':
    main()
